  Future<PaymentResult> buyInAppProduct(ProductDetails product, {String? applicationUserName}) async {
    final param = PurchaseParam(productDetails: product, applicationUserName: applicationUserName);
    final completer = Completer<PaymentResult>();

    late StreamSubscription<PaymentResult> sub;
    sub = results.listen((event) {
      if (!completer.isCompleted && event.transactionId != null) {
        completer.complete(event);
      }
    });

    try {
      await _iap.buyConsumable(
        purchaseParam: param,
        autoConsume: false,
