    } catch (e) {
      return PaymentResult(success: false, status: 'failed', message: e.toString());
    } finally {
      await sub.cancel();
    }
  }

  Future<PaymentResult> completePurchase(PurchaseDetails purchase) async {
    if (purchase.pendingCompletePurchase) {
      await _iap.completePurchase(purchase);
